<?php
namespace App\Modules\Hr\Training\Models;
use App\Models\HrFile; use App\Modules\Hr\Core\Traits\BelongsToLegalEntity; use App\Modules\Hr\Personnel\Models\HrEmployee; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo;
class HrCertificate extends Model { use BelongsToLegalEntity; protected $fillable=['legal_entity_id','employee_id','course_id','enrollment_id','certificate_number','issued_on','expires_on','file_id','status']; protected function casts():array{return ['issued_on'=>'date','expires_on'=>'date'];} public function employee():BelongsTo{return $this->belongsTo(HrEmployee::class);} public function course():BelongsTo{return $this->belongsTo(HrTrainingCourse::class,'course_id');} public function enrollment():BelongsTo{return $this->belongsTo(HrTrainingEnrollment::class,'enrollment_id');} public function file():BelongsTo{return $this->belongsTo(HrFile::class,'file_id');} public function getEffectiveStatusAttribute():string{return $this->expires_on?->isPast()?'expired':$this->status;} }
